import { createBatchCorrection } from './task13';

describe('createBatchCorrection', () => {
  it('selects and deselects cells', () => {
    const batch = createBatchCorrection();
    batch.toggleCell(1, 2);
    expect(batch.selectedCells.length).toBe(1);
    batch.toggleCell(1, 2);
    expect(batch.selectedCells.length).toBe(0);
  });

  it('tracks multiple cells', () => {
    const batch = createBatchCorrection();
    batch.toggleCell(1, 2);
    batch.toggleCell(3, 4);
    expect(batch.selectedCells.length).toBe(2);
  });

  it('clears selection and returns count', () => {
    const batch = createBatchCorrection();
    batch.toggleCell(1, 2);
    batch.toggleCell(3, 4);
    const count = batch.clearSelection();
    expect(count).toBe(2);
    expect(batch.selectedCells.length).toBe(0);
  });
});
